compliant.code:
// Compliant: Remove unnecessary conditional
log.Println("Processing...")
return true

// Compliant: Different logic for each branch
switch status {
case "active":
    log.Println("User is active")
    return true
case "pending":
    log.Println("Waiting for approval")
    return false
case "inactive":
    log.Println("User is inactive")
    return false
}

// Compliant: Role-specific behavior
sendNotification("Welcome")
updateLastLogin()
if user.Role == "admin" {
    grantAdminPrivileges()
}
